#include <stdio.h>
#include <string.h>

int main(void) {
    /* Chaque enregistrement fait exactement 10 chars */
    const char *records = "AAAAAAAAAA" "BBBBBBBBBB" "CCCCCCCCCC" "DDDDDDDDDD" "EEEEEEEEEE";
    FILE *f = fmemopen((void *)records, strlen(records), "r");
    if (!f) return 1;

    char buf[11];
    long size;

    /* Taille totale */
    fseek(f, 0, SEEK_END);
    size = ftell(f);
    printf("Size: %ld bytes\n", size);
    printf("Records: %ld\n", size / 10);

    /* Lire enregistrement 3 (index 2, offset 20) */
    fseek(f, 2 * 10, SEEK_SET);
    fread(buf, 1, 10, f);
    buf[10] = 0;
    printf("Record 3: %s\n", buf);

    /* Position courante */
    printf("Position: %ld\n", ftell(f));

    /* Reculer de 10 pour relire le meme */
    fseek(f, -10, SEEK_CUR);
    fread(buf, 1, 10, f);
    buf[10] = 0;
    printf("Re-read: %s\n", buf);

    fclose(f);
    return 0;
}

