/* == EXEMPLE =======================================
 * Naviguer dans un fichier de mots de 5 lettres
 * fseek(SEEK_SET) pour accès direct par index
 * ================================================= */
void example_seek(void) {
    const char *words = "alphabravocharl";
    FILE *f = fmemopen((void *)words, 15, "r");
    if (!f) return;
    char w[6];
    fseek(f, 5, SEEK_SET); /* mot index 1 */
    fread(w, 1, 5, f); w[5] = 0;
    printf("Word 2: %s\n", w); /* bravo */
    fseek(f, 0, SEEK_SET); /* retour au debut */
    fread(w, 1, 5, f); w[5] = 0;
    printf("Word 1: %s\n", w); /* alpha */
    fclose(f);
}

